public static long solve(long[] nums) {
    int n = nums.length;
    if (n == 1) return 0;
    int[] a = new int[n];
    for (int i = 0; i < n; i++) {
        a[i] = (int) nums[i];
    }
    boolean sorted = true;
    for (int i = 0; i < n; i++) {
        if (a[i] != i) {
            sorted = false;
            break;
        }
    }
    if (sorted) return 0;
    int[] pos = new int[n];
    for (int i = 0; i < n; i++) {
        pos[a[i]] = i;
    }
    int ans = 0;
    for (int bit = 20; bit >= 0; bit--) {
        int candidate = ans | (1 << bit);
        int[] parent = new int[n];
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }
        java.util.Map<Integer, Integer> map = new java.util.HashMap<>();
        for (int i = 0; i < n; i++) {
            if ((a[i] & candidate) == candidate) {
                int x = a[i] & ~candidate;
                if (map.containsKey(x)) {
                    int j = map.get(x);
                    int ri = find(parent, i);
                    int rj = find(parent, j);
                    if (ri != rj) {
                        parent[ri] = rj;
                    }
                } else {
                    map.put(x, i);
                }
            }
        }
        if (map.containsKey(0)) {
            int base = map.get(0);
            int rbase = find(parent, base);
            for (int i = 0; i < n; i++) {
                if ((a[i] & candidate) == candidate) {
                    int ri = find(parent, i);
                    if (ri != rbase) {
                        parent[ri] = rbase;
                    }
                }
            }
        }
        boolean valid = true;
        for (int i = 0; i < n; i++) {
            int indexOfI = pos[i];
            int r1 = find(parent, i);
            int r2 = find(parent, indexOfI);
            if (r1 != r2) {
                valid = false;
                break;
            }
        }
        if (valid) {
            ans = candidate;
        }
    }
    return ans;
}

private static int find(int[] parent, int x) {
    if (parent[x] != x) {
        parent[x] = find(parent, parent[x]);
    }
    return parent[x];
}
